class Solution:
    def findMaximumLength(self, nums: List[int]) -> int:
        total_sum = sum(nums)
        current_sum = 0
        max_length = 0
        current_length = 0

        for num in nums:
            current_sum += num
            if current_sum >= total_sum - current_sum:
                current_length += 1
                max_length = max(max_length, current_length)
            else:
                current_length = 0

        return max_length
